// Code (Prepare State Input)
// ---------------------------
// Loads conversation state from the DB row and latest message from Slack.

// 1) Load current DB row (conversation state) from previous node
const dbRow = $json || {};

// 2) Load latest Slack message from the trigger
// Ensure your trigger node is named exactly "Slack Trigger"
// const slack = $node["Slack Trigger"].json || {};
const slack = $('When Executed by Another Workflow').item.json || {};

// Helper: extract human-readable text from Slack payload
function extractSlackText(msg) {
  if (!msg) return '';

  // Plain text
  if (msg.text && typeof msg.text === 'string') return msg.text.trim();

  // Rich Text / Block Kit
  if (Array.isArray(msg.blocks) && msg.blocks.length > 0) {
    const block = msg.blocks[0];
    if (block.elements && block.elements.length > 0 && block.elements[0].elements) {
      const textEl = block.elements[0].elements.find(e => e.type === 'text');
      if (textEl && textEl.text) return textEl.text.trim();
    }
  }
  return '';
}

// Helper: Safe Boolean Converter (Handles "true"/"yes" strings from DB)
function safeBool(val) {
  if (val === true || val === 'true' || val === 'Yes' || val === 'yes' || val === '1') return true;
  if (val === false || val === 'false' || val === 'No' || val === 'no' || val === '0') return false;
  return null; // Return null if undefined so we know it hasn't been asked yet
}

// 3) Hydrate answer state from DB columns
let answers = {
  // Boolean Flags
  deal_confirmed:     safeBool(dbRow.deal_confirmed),
  resolved_now:       safeBool(dbRow.resolved_now),
  urgent:             safeBool(dbRow.urgent),
  solved_without_ops: safeBool(dbRow.solved_without_ops),
  payment_involved:   safeBool(dbRow.payment_involved),
  post_trip:          safeBool(dbRow.post_trip),
  ops_required: safeBool(dbRow.ops_required),

  // Text Fields
  description:        dbRow.description || '',
  action_taken:      dbRow.action_taken || '', // Stores answer for both Branch A & B
  desired_action:    dbRow.desired_action || '',
  refund_amount:      dbRow.refund_amount || ''
};

// 4) Determine current step
// If DB has no step, assume we are at the start
const step =
  dbRow.current_step && typeof dbRow.current_step === 'string'
    ? dbRow.current_step
    : 'awaiting_deal_confirmation';

// 5) Get IDs (Thread, Channel, User, Group)
const thread_ts =
  dbRow.thread_ts ||
  slack.body?.event?.thread_ts ||
  slack.thread_ts ||
  slack.ts ||
  null;

const channel =
  dbRow.channel ||
  slack.channel ||
  slack.body?.event?.channel ||
  null;

const user_id =
  dbRow.user_id ||
  slack.user ||
  slack.user_id ||
  slack.body?.event?.user ||
  null;

const group_id = dbRow.group_id || null;

// 6) Get latest message text
const messageText = extractSlackText(slack.body?.event || slack);

// 7) Output
return [{
  thread_ts,
  channel,
  user_id,
  group_id,
  current_step: step,
  answers,
  message: messageText,
}];

// Code node: "Decide Next Steps"
// Logic Flow:
// 1. Verify Deal -> 2. Description -> 3. Resolved Now? (BRANCHING POINT)
// BRANCH A (No/Active): 4A. Urgent? -> 5A. Actions Taken -> 6A. Desired Outcome -> Merge
// BRANCH B (Yes/Resolved): 4B. Actions Taken -> 5B. Ops Help? -> Merge
// MERGE: 7. Payment? -> (If Yes) 7.5 Amount -> 8. Post Trip

// ---------- helpers ----------
function parseYesNo(text) {
  if (!text) return null;
  const t = text.trim().toLowerCase();
  if (/(^|\b)(y|yes|yeah|yep|correct|true)/.test(t)) return true;
  if (/(^|\b)(n|no|nope|false|wrong)/.test(t))   return false;
  return null;
}

// ---------- load state ----------
const item  = $json;
let step    = item.current_step || 'awaiting_deal_confirmation';
// Use answers from previous node or init empty
let answers = item.answers || {};
const text  = (item.message || '').trim();

let next_question = null;

// ---------- RESET COMMAND ----------
// Allows user to restart if they get stuck
if (text.toLowerCase() === 'reset' || text.toLowerCase() === 'restart') {
  return [{
    ...item,
    current_step: 'awaiting_deal_confirmation',
    next_question: '🔄 Reset. Is this the correct trip? (yes/no)',
    answers: {}
  }];
}

// ---------- STATE MACHINE ----------
switch (step) {

  // STEP 1: Verify Deal
  case 'awaiting_deal_confirmation': {
    const yn = parseYesNo(text);
    if (yn === null) {
      next_question = `Is this the correct trip (Group ID ${item.group_id})? (yes/no)`;
    } else {
      answers.deal_confirmed = yn;
      if (!yn) {
        step = 'completed';
        next_question = null; // Exit flow
      } else {
        step = 'ask_description';
        next_question = 'Got it. Please provide a summary/description of the issue.';
      }
    }
    break;
  }

  // STEP 2: Description
  case 'ask_description': {
    if (!text) {
      next_question = 'Please provide a summary/description of the issue.';
    } else {
      answers.description = text;
      // Move to Logic Gate
      step = 'ask_is_resolved';
      next_question = 'Has the issue been resolved? (yes/no)';
    }
    break;
  }

  // STEP 3: The Logic Gate (Active vs Resolved)
  case 'ask_is_resolved': {
    const yn = parseYesNo(text);
    if (yn === null) {
      next_question = 'Is the issue currently resolved? Please answer yes or no.';
    } else {
      answers.resolved_now = yn;

      if (yn === false) {
        // --- BRANCH A: ACTIVE ISSUE (No) ---
        step = 'ask_urgency';
        next_question = 'Is this an urgent issue? (yes/no)';
      } else {
        // --- BRANCH B: RESOLVED ISSUE (Yes) ---
        answers.urgent = false;
        step = 'ask_actions_resolved';
        next_question = 'What actions or steps were taken to resolve the issue?';
      }
    }
    break;
  }

  // ================= BRANCH A (Active) =================

  // STEP 4A: Urgency
  case 'ask_urgency': {
    const yn = parseYesNo(text);
    if (yn === null) {
      next_question = 'Is this an urgent issue? (yes/no)';
    } else {
      answers.urgent = yn;
      step = 'ask_ops_required';
      next_question = 'Does this issue require OPS support?';
    }
    break;
  }

  // STEP 4B: Ask Ops Support
  case 'ask_ops_required': {
    const yn = parseYesNo(text);
    if (yn === null) {
      next_question = 'Does this issue require OPS support?';
    } else {
      answers.ops_required = yn;
      step = 'ask_actions_active';
      next_question = 'What actions have been taken so far?';
    }
    break;
  }

  // STEP 5A: Actions Taken (Active)
  case 'ask_actions_active': {
    if (!text) {
      next_question = 'What actions have been taken so far?';
    } else {
      answers.action_taken = text;
      step = 'ask_desired_outcome';
      next_question = 'What is the desired outcome or solution?';
    }
    break;
  }

  // STEP 6A: Desired Outcome (Active)
  case 'ask_desired_outcome': {
    if (!text) {
      next_question = 'What is the desired outcome or solution?';
    } else {
      answers.desired_action = text;
      // Merge to Finance
      step = 'ask_payment';
      next_question = 'Did this involve a payment on [Your Agency] or any refund/credits? (yes/no)';
    }
    break;
  }

  // ================= BRANCH B (Resolved) =================

  // STEP 4B: Actions Taken (Resolved)
  case 'ask_actions_resolved': {
    if (!text) {
      next_question = 'What actions were taken to resolve this?';
    } else {
      answers.action_taken = text;
      step = 'ask_ops_help';
      next_question = 'Did it require OPS help? (yes/no)';
    }
    break;
  }

  // STEP 5B: Ops Help
  case 'ask_ops_help': {
    const yn = parseYesNo(text);
    if (yn === null) {
      next_question = 'Did it require OPS help? (yes/no)';
    } else {
      // Logic: If "Yes" it required Ops -> solved_without_ops is FALSE
      // If "No" it didn't require Ops -> solved_without_ops is TRUE
      answers.solved_without_ops = !yn;

      // Merge to Finance
      step = 'ask_payment';
      next_question = 'Did this involve a payment on [Your Agency] or any refund/credits? (yes/no)';
    }
    break;
  }

  // ================= MERGE (Financials) =================

  // STEP 7: Payment Check
  case 'ask_payment': {
    const yn = parseYesNo(text);
    if (yn === null) {
      next_question = 'Did this involve a payment on [Your Agency] or any refund/credits? (yes/no)';
    } else {
      answers.payment_involved = yn;
      if (yn === true) {
        // If YES, ask Amount
        step = 'ask_refund_amount';
        next_question = 'What was the exact amount refunded / payed? (e.g.,50 USD)';
      } else {
        // If NO, skip to Post Trip
        step = 'ask_post_trip';
        next_question = 'Should this also be tracked as a *post-trip complaint*? (yes/no)';
      }
    }
    break;
  }

  // STEP 7.5: Refund Amount (Only if Payment involved)
  case 'ask_refund_amount': {
    if (!text) {
      next_question = 'Please specify the exact amount refunded / payed (e.g.,50 USD).';
    } else {
      answers.refund_amount = text;
      step = 'ask_post_trip';
      next_question = 'Should this also be tracked as a *post-trip complaint*? (yes/no)';
    }
    break;
  }

  // STEP 8: Post Trip Tagging
  case 'ask_post_trip': {
    const yn = parseYesNo(text);
    if (yn === null) {
      next_question = 'Should this also be tracked as a *post-trip complaint*? (yes/no)';
    } else {
      answers.post_trip = yn;
      step = 'completed';
      next_question = null;
    }
    break;
  }

  default: {
    step = 'completed';
    next_question = null;
    break;
  }
}

// ... [Keep all the previous switch(step) logic exactly the same] ...

// ---------- Logic for Ticket Flags & Jira Outcome ----------

let createTickets = {
  cs_on_trip:  false,
  ops_on_trip: false,
  ops_refund:  false,
  post_trip:   !!answers.post_trip,
};

let jiraOutcome = '';

if (step === 'completed' && answers.deal_confirmed) {

  // 1. Mandatory CS Ticket
  createTickets.cs_on_trip = true;

  // 2. OPS Ticket Logic (Updated for new flow)
  // If Unresolved: Check 'ops_required'
  // If Resolved: Check if it was NOT solved without ops (meaning !solved_without_ops)
  if ((!answers.resolved_now && answers.ops_required) || 
      (answers.resolved_now && answers.solved_without_ops === false)) {
    createTickets.ops_on_trip = true;
  }

  // 3. Finance Ticket Logic
  if (answers.payment_involved) {
    createTickets.ops_refund = true;
  }

  // 4. Generate Jira Outcome Text (New Logic)

  if (!answers.resolved_now) {
    // --- UNRESOLVED CASES ---

    if (answers.urgent) {
      // URGENT
      if (answers.ops_required && answers.payment_involved) {
        jiraOutcome = 'Unresolved Urgent - Escalate to OPS - Refund Required';
      } else {
        // Assumes OPS required (based on your request structure)
        jiraOutcome = 'Unresolved Urgent - Escalate to OPS';
      }
    } else {
      // NOT URGENT
      if (answers.ops_required && answers.payment_involved) {
        jiraOutcome = 'Unresolved - Escalate to OPS - Refund Required';
      } else {
        jiraOutcome = 'Unresolved - Escalate to OPS';
      }
    }

  } else {
    // --- RESOLVED CASES ---

    if (answers.solved_without_ops) {
      // Case A: Resolved WITHOUT Ops
      if (answers.payment_involved) {
        jiraOutcome = 'Resolved without OPS - Refund Required';
      } else {
        jiraOutcome = 'Resolved without OPS - No Refund Required';
      }
    } else {
      // Case B: Resolved WITH Ops (solved_without_ops is false)
      if (answers.payment_involved) {
        jiraOutcome = 'Resolved by OPS - Refund Required';
      } else {
        jiraOutcome = 'Resolved by OPS - No Refund Required';
      }
    }
  }

} else if (step === 'completed' && !answers.deal_confirmed) {
  jiraOutcome = 'Trip not confirmed – no tickets created';
}

// ... [Keep the return statement exactly the same] ...

// ---------- RETURN ----------
return [{
  thread_ts:    item.thread_ts,
  channel:      item.channel,
  user_id:      item.user_id,
  group_id:     item.group_id,
  current_step: step,
  answers,
  next_question,
  createTickets,
  jiraOutcome,
}];

